// /app/api/metrics/stats/route.ts
// All 20+ stat card values fetched in one Promise.all — single round trip
export async function GET() {
  const PROM = process.env.PROMETHEUS_URL;

  const query = (q: string) =>
    fetch(`${PROM}/api/v1/query?query=${encodeURIComponent(q)}`)
      .then(r => r.json())
      .then(d => parseFloat(d.data.result[0]?.value[1] ?? '0'));

  const [cpu, temp, powerLive, powerAvg, ram, disk, uptime, swap] =
    await Promise.all([
      query('100 - (avg(rate(node_cpu_seconds_total{mode="idle"}[1m])) * 100)'),
      query('node_hwmon_temp_celsius{sensor="temp1"}'),
      query('scaph_host_power_microwatts / 1000000'),
      query('avg_over_time(scaph_host_power_microwatts[1h:10s]) / 1000000'),
      query('(1 - (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes)) * 100'),
      query('(1 - (node_filesystem_avail_bytes{mountpoint="/"} / node_filesystem_size_bytes{mountpoint="/"})) * 100'),
      query('time() - node_boot_time_seconds'),
      query('(node_memory_SwapTotal_bytes - node_memory_SwapFree_bytes) / node_memory_SwapTotal_bytes * 100'),
    ]);

  // Estimated monthly electricity cost
  const monthlyCost = (powerAvg * 24 * 30) / 1000 * 6; // ₹6/kWh

  return Response.json({ cpu, temp, powerLive, powerAvg, monthlyCost, ram, disk, uptime, swap });
}
